import{_ as s,W as l,X as o,Z as e,$ as n,a0 as a,a1 as t,D as d}from"./framework-c9619a7b.js";const r={},c=e("h2",{id:"简介",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),n(" 简介")],-1),p=e("p",null,"参考：",-1),u={href:"https://pve.proxmox.com/wiki/PCI_Passthrough",target:"_blank",rel:"noopener noreferrer"},m={href:"https://zhuanlan.zhihu.com/p/614820460?utm_campaign=shareopn&utm_medium=social&utm_oi=790165242284998656&utm_psn=1646204336614219777&utm_source=wechat_session",target:"_blank",rel:"noopener noreferrer"},v=t(`<h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><ol><li>修改<code>/etc/default/grub</code></li></ol><p>(可能本来就有)</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 将 GRUB_CMDLINE_LINUX_DEFAULT=&quot;quiet&quot;</span>
<span class="token comment"># 替换为：</span>
<span class="token assign-left variable">GRUB_CMDLINE_LINUX_DEFAULT</span><span class="token operator">=</span><span class="token string">&quot;quiet intel_iommu=on iommu=pt video=vesafb:off video=efifb:off&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>重启后，验证：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">dmesg</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-e</span> DMAR <span class="token parameter variable">-e</span> IOMMU
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230528164131.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="2"><li>修改<code>/etc/modules</code></li></ol><p>添加以下内容(部分可能本来就有)</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>vfio
vfio_iommu_type1
vfio_pci
vfio_virqfd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>修改<code>/etc/modprobe.d/blacklist.conf</code></li></ol><p>添加驱动黑名单(根据自己显卡类型选择)</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># block AMD driver</span>
blacklist radeon
blacklist amdgpu
​
<span class="token comment"># block NVIDIA driver</span>
blacklist nouveau
blacklist nvidia
blacklist nvidiafb
​
<span class="token comment"># block INTEL driver</span>
blacklist snd_hda_intel
blacklist snd_hda_codec_hdmi
blacklist i915
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>检查IOMMU中断映射(IOMMU Interrupt Remapping)</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">dmesg</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&#39;remapping&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230528165403.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>出现下面之一，视为正常：</p><ul><li>&quot;AMD-Vi: Interrupt remapping enabled&quot;</li><li>&quot;DMAR-IR: Enabled IRQ remapping in x2apic mode&quot; (&#39;x2apic&#39; can be different on old CPUs, but should still work)</li></ul><p>如果没有，可以允许不安全中断(unsafe interrupts)</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;options vfio_iommu_type1 allow_unsafe_interrupts=1&quot;</span> <span class="token operator">&gt;</span> /etc/modprobe.d/iommu_unsafe_interrupts.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="5"><li>查看和确认设备地址 查看iommu_groups</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230528165617.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>查看设备名称</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230528165742.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="6"><li>向虚拟机中添加PCI设备</li></ol><p>编辑<code>/etc/pve/qemu-server/{vmid}.conf</code>(vmid替换为目标虚拟机编号，如101)</p><p>在文件最后添加下面内容：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 添加一个pci设备</span>
hostpci0: 01:00.0

<span class="token comment"># 添加多个pci设备</span>
hostpci0: 01:00.0<span class="token punctuation">;</span>01:00.1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>保存后，在网页上勾选<code>PCI-Express</code></p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230528170631.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><mark>未成功</mark></p><ul><li>USB直通</li></ul>`,32),b={href:"https://pve.proxmox.com/wiki/USB_physical_port_mapping",target:"_blank",rel:"noopener noreferrer"};function g(h,_){const i=d("ExternalLinkIcon");return l(),o("div",null,[c,p,e("ol",null,[e("li",null,[e("a",u,[n("https://pve.proxmox.com/wiki/PCI_Passthrough"),a(i)])]),e("li",null,[e("a",m,[n("知乎 |【NAS】PVE的简单使用教程、调优、常见问题汇总"),a(i)])])]),v,e("p",null,[n("参考："),e("a",b,[n("https://pve.proxmox.com/wiki/USB_physical_port_mapping"),a(i)])])])}const k=s(r,[["render",g],["__file","ProxmoxVE核显直通.html.vue"]]);export{k as default};
